@startuml
skinparam packageStyle rectangle

package "github" {
    namespace weichware10.util.gui {
        class AbsScene <<C>> {
            + InitResult initialize(URL fxml) : green circle
            - void setMenuBar(MenuBar menuBar, Parent root) : red square
            * InitResult start(Stage primaryStage, URL fxml, Parent root, AbsSceneController controller, String title, MenuBar menuBar, Integer width, Integer height, String icon) : blue triangle up
        }

        class Log <<C>> {
            # Stage logStage : orange diamond
            # Parent root : yellow starburst
            ~ SimpleBooleanProperty visibleProperty : purple pentagon
            ^ ObservableBooleanValue visible : cyan hexagon
            & boolean isVisible() : brown octagon
            ! void show() : pink lightning bolt
            ? void hide() : gray cloud
            $ void close() : teal infinity symbol
            % void log(String content, String type) : lime checkmark
        }

        abstract class AbsScene$InitResult <<abstract C>> {
            o Parent root : white circle outline
            c AbsSceneController controller : black crosshatch
            d InitResult(Parent root, AbsSceneController controller) : dark grey filled diamond
        }

        interface ILoggable <<interface>> {
            e void addListener(LogEventListener listener); // Event-driven logging capability
        }

        note right of Log::log\n  Logs messages to console/file/database based on configuration.\nSupports async writes via executor service for performance-critical paths. 
